import sys
it = iter(sys.stdin.read().split())
n = int(next(it))

def generate_binary_strings(n):
    if n == 1:
        return ['0', '1']
    else:
        prev_strings = generate_binary_strings(n-1)
        strings = []
        for string in prev_strings:
            strings.append(string + '0')
            if string[-1] == '0':
                strings.append(string + '1')
        return strings

binary_strings = generate_binary_strings(n)
print(len(binary_strings))
for string in binary_strings:
    print(string)

