#include <bits/stdc++.h>
using namespace std;
int main() {
    int n;
    cin >> n;
    vector<string> binary_strings;
    if (n == 1) {
        binary_strings.push_back("0");
        binary_strings.push_back("1");
    } else {
        vector<string> prev_strings = binary_strings;
        for (int i = 0; i < n; i++) {
            prev_strings.clear();
            if (i == 0) {
                prev_strings.push_back("0");
                prev_strings.push_back("1");
            } else {
                for (const auto& string : binary_strings) {
                    prev_strings.push_back(string + "0");
                    if (string.back() == '0') {
                        prev_strings.push_back(string + "1");
                    }
                }
            }
            binary_strings = prev_strings;
        }
    }
    cout << binary_strings.size() << endl;
    for (const auto& string : binary_strings) {
        cout << string << endl;
    }
    return 0;
}
